      <path d="M12 2C6.5 2 2 6.5 2 12c0 2 .5 3.5 1.5 4.5L8 12.5" />
      <path d="M22 2s-4.5.5-7.5 3.5L11.5 8l3.5 3.5 2.5-3C20.5 5.5 22 2 22 2z" />
      <path d="M9 15l-1.5-.5c-3-1-5-3.5-5-3.5s2.5 1 5.5 2l1 2z" />
