};

// ─── NAVBAR ───────────────────────────────────────────────────────────────────
const NAV_LINKS = ["Home", "About", "Academics", "Achievements", "Members", "Gallery", "Contact"];

const PublicNav = ({ current, onNavigate, onGoToLogin }) => {
  const [menuOpen, setMenuOpen] = useState(false);

  return (
    <>
      <nav
        style={{
          position: "fixed",
          top: 0,
          left: 0,
          right: 0,
          zIndex: 1000,
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          padding: "0 24px",
          height: 70,
          background: "rgba(6,4,15,.88)",
          backdropFilter: "blur(24px)",
          borderBottom: `1px solid ${T.border}`,
          boxShadow: "0 4px 30px rgba(0,0,0,0.4)"
        }}
      >
        {/* Logo */}
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 12,
            marginLeft: 10,

            fontFamily: "Syne",
            fontSize: 20,
            fontWeight: 900,
            cursor: "pointer"
          }}
          onClick={() => onNavigate("home")}
        >
          <img src="logo.png" alt="image" height={50} width={130} />
        </div>

        {/* Desktop Menu */}
        <div
          className="desktop-menu"
          style={{
            display: "flex",
            alignItems: "center",
            gap: 28,
          }}
        >
          {NAV_LINKS.map((l) => {
            const isActive = current === l.toLowerCase();
            return (
              <button
                key={l}
                onClick={() => onNavigate(l.toLowerCase())}
                style={{
                  background: "none",
                  border: "none",
                  cursor: "pointer",
                  fontSize: 13,
                  fontWeight: 600,
                  color: isActive ? T.accent : T.text,
                  position: "relative",
                  padding: "6px 2px",
                  transition: "color 0.3s ease",
                  textTransform: "uppercase",
                  letterSpacing: "0.8px"
                }}
              >
                {l}
                {isActive && (
                  <span style={{
                    position: "absolute",
                    bottom: 0,
                    left: 0,
                    right: 0,
                    height: 2,
                    background: `linear-gradient(90deg, ${T.primary}, ${T.accent})`,
                    borderRadius: 2
                  }} />
                )}
              </button>
            );
          })}
        </div>

        {/* Desktop Login Button */}
        <button
          className="desktop-login"
          onClick={onGoToLogin}
          style={{
            background: `linear-gradient(135deg, ${T.primary}, ${T.primaryL})`,
            border: "none",
            color: "#fff",
            padding: "10px 24px",
            borderRadius: 50,
            fontWeight: 800,
            fontSize: 13,
            cursor: "pointer",
            boxShadow: `0 4px 14px ${T.primary}40`,
            transition: "all 0.3s ease",
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.transform = "translateY(-2px)";
            e.currentTarget.style.boxShadow = `0 6px 20px ${T.primary}60`;
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.transform = "translateY(0)";
            e.currentTarget.style.boxShadow = `0 4px 14px ${T.primary}40`;
          }}
        >
          🚀 Login
        </button>

        {/* Mobile Hamburger */}
        <div
          className="mobile-menu-icon"
          onClick={() => setMenuOpen(!menuOpen)}
          style={{
            display: "none",
            fontSize: 24,
            cursor: "pointer",
            color: "#fff",
          }}
        >
          ☰
        </div>
      </nav>

      {/* Mobile Dropdown */}
      {menuOpen && (
        <div
          style={{
            position: "fixed",
            top: 70,
            left: 0,
            right: 0,
            background: "rgba(10,10,20,0.98)",
            backdropFilter: "blur(24px)",
            padding: "24px",
            display: "flex",
            flexDirection: "column",
            gap: 18,
            zIndex: 999,
            borderBottom: `1px solid ${T.border}`
          }}
        >
          {NAV_LINKS.map((l) => (
            <button
              key={l}
              onClick={() => {
                onNavigate(l.toLowerCase());
                setMenuOpen(false);
              }}
              style={{
                background: "none",
                border: "none",
                textAlign: "left",
                fontSize: 16,
                fontWeight: 600,
                color: current === l.toLowerCase() ? T.accent : "#fff",
                cursor: "pointer",
              }}
            >
              {l}
            </button>
          ))}

          <button
            onClick={() => {
              onGoToLogin();
              setMenuOpen(false);
            }}
            style={{
              marginTop: 12,
              background: `linear-gradient(135deg, ${T.primary}, ${T.accent})`,
              border: "none",
              color: "#fff",
              padding: "12px",
              borderRadius: 30,
              fontWeight: 700,
              cursor: "pointer",
            }}
